+  // Only enable the credux instruction for reduction on the full warp, as we saw perf regression
+  // for GROUP_SIZE < 32, where we need to iterate over #(WARP_SIZE/GROUP_SIZE) groups in the warp
+  if constexpr (GROUP_SIZE == WARP_SIZE) {
+    // For sm_100a arch, we can use redux.sync.op{.abs.}{.NaN}.f32 instruction to reduce the min/max
+    // value
+    // https://docs.nvidia.com/cuda/parallel-thread-execution/#parallel-synchronization-and-communication-instructions-redux-sync
+    asm volatile("redux.sync.max.f32 %0, %1, %2;" : "=f"(max_val) : "f"(m), "r"(mask));
+    return max_val;
+  }
+#endif
+#pragma unroll
+  for (int delta = GROUP_SIZE / 2; delta > 0; delta /= 2) {
+    const float other_m = __shfl_down_sync(mask, max_val, delta);
+    __builtin_assume(max_val >= 0);
+    __builtin_assume(other_m >= 0);
+    max_val = fmaxf(max_val, other_m);
+  }
+  return max_val;
