+    asm volatile("red.release.gpu.global.add.s32 [%0], %1;" ::"l"(barrier), "r"(step));
+    for (int found = -1; found != expected;) {
+      asm volatile("ld.global.acquire.gpu.b32 %0, [%1];" : "=r"(found) : "l"(barrier));
+    }
+  }
+
+  inline __device__ void sync(uint32_t threads_per_cta) {
+    // ALL THREADS MUST ENTER!
+
+    // We switch barrier every iteration.
+    int* barrier = phase_counter_ & 0x1 ? b1_ : b0_;
+    // We decrement every other iteration.
+    bool dec = phase_counter_ & 0x2;
+    int step = dec ? -1 : 1;
+    int expected = dec ? 0 : CTAS_PER_ROW;
+    // There are only 4 phases: up/down for b0/b1.
+    phase_counter_ = (phase_counter_ + 1) & 0x3;
+
+    if (0 == tidx_) {
+      spin_wait_(barrier, step, expected);
+    }
+
+    // CTA waits for thread 0
+    utils::namedBarrierSync(0, threads_per_cta);
+  }
+
+  int phase_counter_;
+  int* b0_;
+  int* b1_;
+  uint32_t tidx_;
+};
+
+////////////////////////////////////////////////////////////////////////////////////////////////////
+//// LayerNorm Reduction and stats computation
+// NOTE: WHOLE_CTA means if we'll use one empty mbarrier for inter-CTA sync using cluster.
+// In the TMA LN engines it should be "true" since we're syncing the whole CTA with one empty
+// mbarrier, while in the APEX LN engines it should be "false" as there's one empty mbarrier per
+// warp m (and therefore WARPS_M empty mbarriers in total)
+template <typename T, uint32_t CTAS_PER_ROW, uint32_t WARPS_M, uint32_t WARPS_N, bool USE_CLUSTER,
+          bool WHOLE_CTA>
+struct Reducer : public Reducer<T, 1, WARPS_M, WARPS_N, USE_CLUSTER, WHOLE_CTA> {
+  using InterCTASync = InterCTASync<CTAS_PER_ROW>;
+  using Base = Reducer<T, 1, WARPS_M, WARPS_N, USE_CLUSTER, WHOLE_CTA>;
+  using Type = typename Base::Type;
+
+  enum { SMEM_BYTES = Base::SMEM_BYTES };
+
+  enum { WS_BARRIER_BYTES = 2 * sizeof(int) };
+  enum { WS_DATA_BYTES = WARPS_M * CTAS_PER_ROW * sizeof(T) };
+
+  // size of the barriers + temporary result per CTA (multiply with CTAS_PER_ROW to get total)
+  enum {
+    WORKSPACE_BYTES_PER_GROUP = Base::WORKSPACE_BYTES_PER_GROUP + WS_BARRIER_BYTES + WS_DATA_BYTES
+  };
+
+  template <typename Params>
+  inline __device__ Reducer(Params& params, uint32_t bidm, uint32_t bidn, uint32_t warp_m,
+                            uint32_t warp_n, uint32_t tidx, uint32_t lane, void* smem,
+                            uint64_t* smem_bar)
+      : Base(params, bidm, bidn, warp_m, warp_n, tidx, lane, smem, smem_bar),
+        inter_cta_(params, bidm, bidn, tidx),
+        bidn_(bidn),  // CTA id within the group.
+        warp_m_(warp_m),
+        w0_(static_cast<T*>(params.workspace) + (bidm * WARPS_M + warp_m) * CTAS_PER_ROW),
+        w1_(w0_ + params.ctas_per_col * WARPS_M * CTAS_PER_ROW),
+        smem_bar_(smem_bar),
+        parity_(0) {
+    // the first several elements are the barriers
+    smem_cga_ = reinterpret_cast<T*>(&smem_bar[WHOLE_CTA ? 2 : (WARPS_M + 1)]);
+  }
+
+  template <typename Op>
+  inline __device__ T allreduce(T data, Op& op, int32_t warps_m) {
+    data = Base::reduce(data, op, warps_m);
+
+    if constexpr (USE_CLUSTER) {
+#if (__CUDA_ARCH__ >= 900) && (CUDART_VERSION >= 12080)
+      auto cluster = cooperative_groups::this_cluster();
+
+      // NOTE: right now only lane 0 has the valid value so that a intra-warp broadcast is required
+      // here. This issue is not in fwd (struct Stats) which does it earlier inside
+      // warp_chan_upd_dynamic().
+      data = utils::shfl_sync_helper(uint32_t(-1), data, 0);
+
+      // Broadcast local results to other CTAs inside the CGA
+      // Size of smem_cga_: [WARPS_M][CTAS_PER_ROW]
+      // Thread 0 sends to block 0, Thread 1 sends to block 1, etc...
+      if ((this->warp_n_ == 0) && (this->lane_ < CTAS_PER_ROW)) {
+        st_async_remote(&smem_cga_[warp_m_ * CTAS_PER_ROW + bidn_], data, this->lane_,
+                        &smem_bar_[WHOLE_CTA ? 0 : WARPS_M]);
+      }
+
+      // Leader thread arrives on local barrier to indicate expected tx count
+      // We can't use (threadIdx.x == 0) directly here because it won't work for TMA
+      if ((this->warp_n_ == 0) && (warp_m_ == 0) && (this->lane_ == 0)) {
+        // It's possible that not all warp_m are active here, therefore, we can't use WARPS_M
+        // directly
+        uint32_t expected_tx_count = sizeof(data) * CTAS_PER_ROW * warps_m;
+        utils::mbarrier_arrive_expect_tx_relaxed_cluster(&smem_bar_[WHOLE_CTA ? 0 : WARPS_M],
+                                                         expected_tx_count);
+      }
+
+      // Wait on local barrier
+      while (!utils::mbarrier_try_wait_parity_relaxed_cluster(&smem_bar_[WHOLE_CTA ? 0 : WARPS_M],
+                                                              parity_)) {
+      }
+      utils::fence_acquire_smem();  // Ensure we can read local smem values that are released by
+                                    // barrier flip
+
+      T total = Zeros<T>::get();
+      if (this->lane_ < CTAS_PER_ROW) {
+        total = smem_cga_[warp_m_ * CTAS_PER_ROW + this->lane_];
+      }
+      utils::fence_release_smem();  // Ensure read of buffer remains ordered before
+                                    // smem_bar.arrive.relaxed
+
+      // Signal barrier is empty.
+      // Each thread must arrive on all the barriers (like an arrive broadcast).
+      // NOTE: here we only let each warp m arrive on the remote barriers of the same warp m (i.e.
+      // the same row), because if we have one empty barrier for the entire CTA, there's a
+      // difficulty how to init the count of the barrier (since some warps could be disabled here).
+      // The downside is we'll need a __syncthreads() here, which doesn't have obvious perf impact
+      // though.
+      // TODO: we could probably have one full bar per row (same as the empty bar) to get rid of the
+      // CTA sync, while the downside is more smem (mbarriers) will be needed.
+      if (!WHOLE_CTA) {
+        utils::namedBarrierSync(0, warps_m * WARPS_N * 32);
+      }
+      for (int other_block_rank = 0; other_block_rank < CTAS_PER_ROW; ++other_block_rank) {
+        uint64_t* remote_bar_empty =
+            cluster.map_shared_rank(&smem_bar_[WHOLE_CTA ? 1 : warp_m_], other_block_rank);
+        utils::mbarrier_arrive_relaxed_cluster(remote_bar_empty);
+      }
+
+      total = Reducer<T, 1, 1, 1, USE_CLUSTER, WHOLE_CTA>::allreduce_(total, op);
+
+      // Wait for remote buffer to be writable again by waiting on local barrier:
+      while (!utils::mbarrier_try_wait_parity_relaxed_cluster(&smem_bar_[WHOLE_CTA ? 1 : warp_m_],
+                                                              parity_)) {
+      }
+      utils::fence_acquire_smem();  // Order wrt st_async_remote
+
+      // Flip parity bit for next iteration
+      parity_ ^= 1;
+
+      return total;
+#else
+      static_assert(true, "Cluster enabled on host side but not available on device");
+#endif
+    } else {
+      // We switch workspace every iteration.
+      T* workspace = inter_cta_.phase_counter_ & 0x1 ? w1_ : w0_;
+
+      // Warp leaders 0 hold the CTA-local results.
+      if (this->warp_n_ == 0 && this->lane_ == 0) {
+        workspace[bidn_] = data;
+      }
+
+      // We need to check for the case where we are using CTA > 1 and WARP_M > 1 and N == 1
+      // Because in this case we cannot rely on the __syncThreads in template<typename T, uint32_t
+      // WARPS_M, uint32_t WARPS_N>::compute (because we will use the specialized template <typename
+      // T, uint32_t WARPS_M>::compute which does not have a sync)
+      if (CTAS_PER_ROW > 1 && WARPS_M > 1 && WARPS_N == 1) {
+        utils::namedBarrierSync(0, warps_m * WARPS_N * 32);
+      }
+
+      // Wait for all CTAS_PER_ROW CTAS in the group to have written their result.
+      inter_cta_.sync(warps_m * WARPS_N * 32);
+
+      T total = Zeros<T>::get();
+
+      // Every warp does the final reduction locally.
+      if constexpr (CTAS_PER_ROW <= THREADS_PER_WARP) {
+        if (this->lane_ < CTAS_PER_ROW) {
+          total = workspace[this->lane_];
+        }
+      } else {
+        static constexpr int32_t LOOP_PER_THREAD =
+            (CTAS_PER_ROW + THREADS_PER_WARP - 1) / THREADS_PER_WARP;
+
+        // Collect stats for the current lane from ctas (#bidn % THREADS_PER_WARP == #lane) and then
+        // do the intra-warp reduction
+        total = workspace[this->lane_];
+#pragma unroll
+        for (int32_t loop_in_thread = 1; loop_in_thread < LOOP_PER_THREAD; ++loop_in_thread) {
+          const int32_t lane_in_loop = this->lane_ + loop_in_thread * THREADS_PER_WARP;
+          if (lane_in_loop < CTAS_PER_ROW) {
+            total = op(total, workspace[lane_in_loop]);
+          }
+        }
+      }
+
+      total = Reducer<T, 1, 1, 1, false, false>::allreduce_(total, op);
+
+      return total;
+    }
+  }
+
+  InterCTASync inter_cta_;
+  T* w0_;
+  T* w1_;
+  int bidn_;
+  int warp_m_;
+
+ private:
+  T* smem_cga_;
+  uint64_t* smem_bar_;
+  int parity_;
+};
+
+template <typename T, uint32_t WARPS_M, bool USE_CLUSTER, bool WHOLE_CTA>
+struct Reducer<T, 1, WARPS_M, 1, USE_CLUSTER, WHOLE_CTA> {
+  using Type = T;
+  enum { SMEM_BYTES = 0 };
+  enum { WORKSPACE_BYTES_PER_GROUP = 0 };
+  enum { THREADS_PER_WARP = 32 };
+
+  template <typename Params>
+  inline __device__ Reducer(Params& params, uint32_t bidm, uint32_t bidn, uint32_t warp_m,
+                            uint32_t warp_n, uint32_t /*tidx*/, uint32_t lane, void* smem,
+                            uint64_t* smem_bar)
+      : warp_n_(warp_n), lane_(lane) {}
+
+  template <typename Op>
+  static inline __device__ T allreduce_(T data, Op& op) {
+#pragma unroll
+    for (int it = 1; it < THREADS_PER_WARP; it *= 2) {
+      data = op(data, utils::warp_shuffle_xor(data, it));
+    }
+    return data;
+  }
+
+  template <typename Op>
+  inline __device__ T allreduce(T data, Op& op, int32_t warps_m) {
+    return allreduce_(data, op);
+  }
+
+ protected:
+  template <typename Op>
+  inline __device__ T reduce(T data, Op& op, int32_t warps_m) {
+// only lane 0 holds the result!
+#pragma unroll
+    for (int it = THREADS_PER_WARP / 2; it > 0; it /= 2) {
+      data = op(data, utils::warp_shuffle_down(data, it));
+    }
+    return data;
+  }
+
+ public:
+  int warp_n_;
+  int lane_;
+};
+
+template <typename T, uint32_t WARPS_M, uint32_t WARPS_N, bool USE_CLUSTER, bool WHOLE_CTA>
+struct Reducer<T, 1, WARPS_M, WARPS_N, USE_CLUSTER, WHOLE_CTA>
+    : public Reducer<T, 1, WARPS_M, 1, USE_CLUSTER, WHOLE_CTA> {
+  using Base = Reducer<T, 1, WARPS_M, 1, USE_CLUSTER, WHOLE_CTA>;
+  using Type = T;
+
+  enum { SMEM_BYTES = Base::SMEM_BYTES + WARPS_M * WARPS_N * sizeof(T) * 2 };
+  enum { WORKSPACE_BYTES_PER_GROUP = 0 };
+  enum { THREADS_PER_WARP = 32 };
+
+  template <typename Params>
+  inline __device__ Reducer(Params& params, uint32_t bidm, uint32_t bidn, uint32_t warp_m,
+                            uint32_t warp_n, uint32_t tidx, uint32_t lane, void* smem,
+                            uint64_t* smem_bar)
+      : Base(params, bidm, bidn, warp_m, warp_n, tidx, lane, smem, smem_bar), use0_(true) {
+    smem0_ = &static_cast<T*>(smem)[warp_m * WARPS_N];
+    smem1_ = smem0_ + WARPS_M * WARPS_N;
+  }
+
+  template <typename Op>
+  inline __device__ T allreduce(T data, Op& op, int32_t warps_m) {
+    T* smem = use0_ ? smem0_ : smem1_;
+    use0_ = !use0_;
+    data = Base::reduce(data, op, warps_m);
+    if (this->lane_ == 0) {
+      smem[this->warp_n_] = data;
+    }
+    // The number matters here. 0 will only use one barrier per block. "1" will use 2 according to
+    // ncu. We should use 0 unless it is absolutely necessary to use seperate barriers.
+    utils::namedBarrierSync(0, warps_m * WARPS_N * 32);
+    T out = Zeros<T>::get();
+#pragma unroll
+    for (int it = 0; it < WARPS_N; it++) {
+      out = op(out, smem[it]);
+    }
+    return out;
+  }
+
+ protected:
+  template <typename Op>
+  inline __device__ T reduce(T data, Op& op, int32_t warps_m) {
+    T* smem = use0_ ? smem0_ : smem1_;
+    use0_ = !use0_;
+    // only intra-CTA group leader holds the result!
+    data = Base::reduce(data, op, warps_m);
+    if (this->lane_ == 0) {
+      smem[this->warp_n_] = data;
+    }
+    utils::namedBarrierSync(0, warps_m * WARPS_N * 32);
+    T out = Zeros<T>::get();
+    if (this->warp_n_ == 0 && this->lane_ == 0) {
+#pragma unroll
+      for (int it = 0; it < WARPS_N; it++) {
+        out = op(out, smem[it]);
+      }
+    }
+    return out;
+  }
+
+ private:
+  T* smem0_;
+  T* smem1_;
+  bool use0_;
+};
+
+////////////////////////////////////////////////////////////////////////////////////////////////////
+template <bool isRMSNorm, typename T, bool handleNan = false>
+inline __device__ void update_norm_stats(T& m_a, T& m2_a, T& n_a, T m_b, T m2_b, T n_b) {
+  const T n_ab = n_a + n_b;
+
+  if constexpr (!isRMSNorm) {
+    const T rn_ab = (handleNan && (n_ab == Zeros<T>::get())) ? Zeros<T>::get() : (1.f / n_ab);
+    const T delta = m_a - m_b;
+    const float m2_ab = m2_a + m2_b + delta * delta * n_a * n_b * rn_ab;
+    const float m_ab = (n_a * m_a + n_b * m_b) * rn_ab;
+    n_a = n_ab;
+    m_a = m_ab;
+    m2_a = m2_ab;
+  } else {
+    const float m2_ab = m2_a + m2_b;
+    n_a = n_ab;
+    m_a = Zeros<T>::get();
+    m2_a = m2_ab;
+  }
+}
+
+template <bool isRMSNorm, typename T, bool handleNan = false>
+inline __device__ void warp_chan_upd_dynamic(T& m_a, T& m2_a, T& n_a, int num_active) {
+  // Assume at least leftmost is valid and init: step = next_pow2(num_active) / 2 (might get NaN
+  // otherwise)
+  int highest_bit_set = (8 * sizeof(num_active)) - __clz(num_active - 1);
+
+#pragma unroll
+  for (int step = (1 << (highest_bit_set - 1)); step > 0; step /= 2) {
+    // Exchange
+    T n_b = utils::warp_shuffle_down(n_a, step);
+    T m_b = (!isRMSNorm ? utils::warp_shuffle_down(m_a, step) : Zeros<T>::get());
+    T m2_b = utils::warp_shuffle_down(m2_a, step);
+    update_norm_stats<isRMSNorm, T, handleNan>(m_a, m2_a, n_a, m_b, m2_b, n_b);
+  }
+  // Intra-warp broadcast (only lane 0 has valid stats).
+  m_a = __shfl_sync(uint32_t(-1), m_a, 0);
+  m2_a = __shfl_sync(uint32_t(-1), m2_a, 0);
+}
+
+////////////////////////////////////////////////////////////////////////////////////////////////////
+// NOTE: WHOLE_CTA means if we'll use one empty mbarrier for inter-CTA sync using cluster.
+// In the TMA LN engines it should be "true" since we're syncing the whole CTA with one empty
+// mbarrier, while in the APEX LN engines it should be "false" as there's one empty mbarrier per
+// warp m (and therefore WARPS_M empty mbarriers in total)
+template <typename T, uint32_t CTAS_PER_ROW, uint32_t WARPS_M, uint32_t WARPS_N, bool USE_CLUSTER,
+          bool WHOLE_CTA>
+struct Stats {
+  // This could be done generically with the Reducer. But then we would have to exchange 3 instead
+  // of 2 fields.
+
+  using InterCTASync = InterCTASync<CTAS_PER_ROW>;
+  using BlockStats = Stats<T, 1, WARPS_M, WARPS_N, USE_CLUSTER, WHOLE_CTA>;
+  using stats_t = typename BlockStats::stats_t;
+
+  enum { SMEM_BYTES = BlockStats::SMEM_BYTES };
+
+  template <typename Params>
+  inline __device__ Stats(Params& params, uint32_t bidm, uint32_t bidn, uint32_t warp_m,
+                          uint32_t warp_n, uint32_t tidx, uint32_t lane, void* smem,
+                          uint64_t* smem_bar)
+      : inter_cta_(params, bidm, bidn, tidx),
+        block_stats_(params, bidm, bidn, warp_m, warp_n, tidx, lane, smem, smem_bar),
+        bidn_(bidn),  // CTA id within the group.
+        w0_(static_cast<stats_t*>(params.workspace) + (bidm * WARPS_M + warp_m) * CTAS_PER_ROW),
+        w1_(w0_ + params.ctas_per_col * WARPS_M * CTAS_PER_ROW),
+        warp_n_(warp_n),
+        warp_m_(warp_m),
+        lane_(lane),
+        smem_bar_(smem_bar),
+        parity_(0) {
+    // the first several elements are the barriers
+    smem_cga_ = reinterpret_cast<stats_t*>(&smem_bar[WHOLE_CTA ? 2 : (WARPS_M + 1)]);
+  }
+
+  template <bool isRMSNorm, uint32_t LDGS, uint32_t NUM_ELTS>
+  inline __device__ stats_t compute(const T (&elts)[LDGS * NUM_ELTS], const T rn, int32_t warps_m) {
+    static constexpr uint32_t N = LDGS * NUM_ELTS;
+    constexpr T ELTS_PER_ROW_PER_CTA = N * WARPS_N * THREADS_PER_WARP;
+    // TODO rn is not really needed here..
+    constexpr T block_rn = 1.f / T(ELTS_PER_ROW_PER_CTA);
+    stats_t block_stats =
+        block_stats_.template compute<isRMSNorm, LDGS, NUM_ELTS>(elts, block_rn, warps_m);
+
+    if constexpr (USE_CLUSTER) {
+#if (__CUDA_ARCH__ >= 900) && (CUDART_VERSION >= 12080)
+      auto cluster = cooperative_groups::this_cluster();
+
+      // Broadcast local results to other CTAs inside the CGA
+      // Size of smem_cga_: [WARPS_M][CTAS_PER_ROW]
+      // Thread 0 sends to block 0, Thread 1 sends to block 1, etc...
+      if ((warp_n_ == 0) && (lane_ < CTAS_PER_ROW)) {
+        st_async_remote(&smem_cga_[warp_m_ * CTAS_PER_ROW + bidn_], block_stats, lane_,
+                        &smem_bar_[WHOLE_CTA ? 0 : WARPS_M]);
+      }
+
+      // Leader thread arrives on local barrier to indicate expected tx count
+      // We can't use (threadIdx.x == 0) directly here because it won't work for TMA
+      if ((warp_n_ == 0) && (warp_m_ == 0) && (lane_ == 0)) {
+        // It's possible that not all warp_m are active here, therefore, we can't use WARPS_M
+        // directly
+        uint32_t expected_tx_count = sizeof(block_stats) * CTAS_PER_ROW * warps_m;
+        utils::mbarrier_arrive_expect_tx_relaxed_cluster(&smem_bar_[WHOLE_CTA ? 0 : WARPS_M],
+                                                         expected_tx_count);
+      }
+
+      // Wait on local barrier
+      while (!utils::mbarrier_try_wait_parity_relaxed_cluster(&smem_bar_[WHOLE_CTA ? 0 : WARPS_M],
+                                                              parity_)) {
+      }
+      utils::fence_acquire_smem();  // Ensure we can read local smem values that are released by
+                                    // barrier flip
+
+      T n = Zeros<T>::get();
+      T m = Zeros<T>::get();
+      T m2 = Zeros<T>::get();
+      if (lane_ < CTAS_PER_ROW) {
+        stats_t result = smem_cga_[warp_m_ * CTAS_PER_ROW + lane_];
+        n = ELTS_PER_ROW_PER_CTA;
+        m = Get<0>::of<stats_t, T>(result);  // should be 0 for RMSNorm
+        m2 = Get<1>::of<stats_t, T>(result);
+      }
+      utils::fence_release_smem();  // Ensure read of buffer remains ordered before
+                                    // smem_bar.arrive.relaxed
+
+      // Signal barrier is empty.
+      // Each thread must arrive on all the barriers (like an arrive broadcast).
+      // NOTE: here we only let each warp m arrive on the remote barriers of the same warp m (i.e.
+      // the same row), because if we have one empty barrier for the entire CTA, there's a
+      // difficulty how to init the count of the barrier (since some warps could be disabled here).
+      // The downside is we'll need a __syncthreads() here, which doesn't have obvious perf impact
+      // though.
+      // TODO: we could probably have one full bar per row (same as the empty bar) to get rid of the
+      // CTA sync, while the downside is more smem (mbarriers) will be needed.
+      if (!WHOLE_CTA) {
+        utils::namedBarrierSync(0, warps_m * WARPS_N * 32);
+      }
+      for (int other_block_rank = 0; other_block_rank < CTAS_PER_ROW; ++other_block_rank) {
+        uint64_t* remote_bar_empty =
+            cluster.map_shared_rank(&smem_bar_[WHOLE_CTA ? 1 : warp_m_], other_block_rank);
+        utils::mbarrier_arrive_relaxed_cluster(remote_bar_empty);
+      }
+
+      warp_chan_upd_dynamic<isRMSNorm, T, !is_power_of_2(CTAS_PER_ROW)>(m, m2, n, CTAS_PER_ROW);
+
+      // Wait for remote buffer to be writable again by waiting on local barrier:
+      while (!utils::mbarrier_try_wait_parity_relaxed_cluster(&smem_bar_[WHOLE_CTA ? 1 : warp_m_],
+                                                              parity_)) {
+      }
+      utils::fence_acquire_smem();  // Order wrt st_async_remote
+
+      // Flip parity bit for next iteration
+      parity_ ^= 1;
+
+      return {m, m2};
+#else
+      static_assert(true, "Cluster enabled on host side but not available on device");
+#endif
+    } else {
+      // We switch workspace every iteration.
+      stats_t* workspace = inter_cta_.phase_counter_ & 0x1 ? w1_ : w0_;
+
+      // Warp leaders 0 hold the CTA-local results.
+      if (warp_n_ == 0 && lane_ == 0) {
+        workspace[bidn_] = block_stats;
+      }
+
+      // We need to check for the case where we are using CTA > 1 and WARP_M > 1 and N == 1
+      // Because in this case we cannot rely on the __syncThreads in template<typename T, uint32_t
+      // WARPS_M, uint32_t WARPS_N>::compute (because we will use the specialized template <typename
+      // T, uint32_t WARPS_M>::compute which does not have a sync) Bug 5221388: For WARPS_M > 1 and
+      // WARPS_N > 1, we also need the sync here, otherwise the stats received in `workspace[lane_]`
+      // may be NaN (as if some stats from the other CTAs are not initialized). Reason unknown yet
+      // and tracked in CL-16775.
+      if (CTAS_PER_ROW > 1 && WARPS_M > 1) {
+        utils::namedBarrierSync(0, warps_m * WARPS_N * 32);
+      }
+
+      // Wait for all CTAS_PER_ROW CTAS in the group to have written their result.
+      inter_cta_.sync(warps_m * WARPS_N * 32);
+
+      T n = Zeros<T>::get();
+      T m = Zeros<T>::get();
+      T m2 = Zeros<T>::get();
+
+      // Every warp does the final reduction locally.
+      if constexpr (CTAS_PER_ROW <= THREADS_PER_WARP) {
+        if (lane_ < CTAS_PER_ROW) {
+          stats_t result = workspace[lane_];
+          n = ELTS_PER_ROW_PER_CTA;
+          m = Get<0>::of<stats_t, T>(result);  // should be 0 for RMSNorm
+          m2 = Get<1>::of<stats_t, T>(result);
+        }
+        warp_chan_upd_dynamic<isRMSNorm, T, !is_power_of_2(CTAS_PER_ROW)>(m, m2, n, CTAS_PER_ROW);
+      } else {
+        static constexpr int32_t LOOP_PER_THREAD =
+            (CTAS_PER_ROW + THREADS_PER_WARP - 1) / THREADS_PER_WARP;
+
+        stats_t curr = workspace[lane_];
+        n = ELTS_PER_ROW_PER_CTA;
+        m = Get<0>::of<stats_t, T>(curr);  // should be 0 for RMSNorm
+        m2 = Get<1>::of<stats_t, T>(curr);
+
+        // Collect stats for the current lane from ctas (#bidn % THREADS_PER_WARP == #lane) and then
+        // do the intra-warp reduction
+#pragma unroll
+        for (int32_t loop_in_thread = 1; loop_in_thread < LOOP_PER_THREAD; ++loop_in_thread) {
+          const int32_t lane_in_loop = lane_ + loop_in_thread * THREADS_PER_WARP;
+          if (lane_in_loop < CTAS_PER_ROW) {
+            curr = workspace[lane_in_loop];
+            T m_b = Get<0>::of<stats_t, T>(curr);
+            T m2_b = Get<1>::of<stats_t, T>(curr);
+            update_norm_stats<isRMSNorm>(m, m2, n, m_b, m2_b, ELTS_PER_ROW_PER_CTA);
+          }
+        }
+        warp_chan_upd_dynamic<isRMSNorm>(m, m2, n, THREADS_PER_WARP);
+      }
+
+      return {m, m2};
+    }
+  }
+
+  InterCTASync inter_cta_;
+  BlockStats block_stats_;
+
+  stats_t* w0_;
+  stats_t* w1_;
+  int bidn_;
+  int warp_n_;
+  int warp_m_;
+  int lane_;
+
+ private:
+  stats_t* smem_cga_;
+  uint64_t* smem_bar_;
+  int parity_;
+};
