+template <typename T, uint32_t WARPS_M, uint32_t WARPS_N, bool USE_CLUSTER, bool WHOLE_CTA>
+struct Stats<T, 1, WARPS_M, WARPS_N, USE_CLUSTER, WHOLE_CTA> {
+  using WarpStats = Stats<T, 1, WARPS_M, 1, USE_CLUSTER, WHOLE_CTA>;
+  using stats_t = typename WarpStats::stats_t;
+
+  enum { SMEM_BYTES = WARPS_M * WARPS_N * sizeof(stats_t) * 2 };
+
+  template <typename Params>
+  inline __device__ Stats(Params& params, uint32_t bidm, uint32_t bidn, uint32_t warp_m,
+                          uint32_t warp_n, uint32_t tidx, uint32_t lane, void* smem,
+                          uint64_t* smem_bar)
+      : warp_stats_(params, bidm, bidn, warp_m, warp_n, tidx, lane, smem, smem_bar), use0_(true) {
+    smem0_ = static_cast<stats_t*>(smem) + warp_m * WARPS_N;
+    smem1_ = smem0_ + WARPS_M * WARPS_N;
+  }
+
+  template <bool isRMSNorm, uint32_t LDGS, uint32_t NUM_ELTS>
+  inline __device__ stats_t compute(const T (&elts)[LDGS * NUM_ELTS], const T rn, int32_t warps_m) {
+    stats_t* smem = use0_ ? smem0_ : smem1_;
+    use0_ = !use0_;
+    // Compute warp local for all WARPS_N
+    static constexpr uint32_t N = LDGS * NUM_ELTS;
+    constexpr T warp_rn = 1.f / T(N * THREADS_PER_WARP);
+    stats_t warp_stats =
+        warp_stats_.template compute<isRMSNorm, LDGS, NUM_ELTS>(elts, warp_rn, warps_m);
+
+    // Each warp warp leader stores its stats
+    const auto warp_n = warp_stats_.reducer_.warp_n_;
+    const auto lane = warp_stats_.reducer_.lane_;
+    if (lane == 0) {
+      smem[warp_n] = warp_stats;
+    }
+    utils::namedBarrierSync(0, warps_m * WARPS_N * 32);
+
+    T n = Zeros<T>::get();
+    T m = Zeros<T>::get();
+    T m2 = Zeros<T>::get();
+
+    if (lane < WARPS_N) {
+      stats_t result = smem[lane];
+      n = N * THREADS_PER_WARP;
+      m = Get<0>::of<stats_t, T>(result);  // should be 0 for RMSNorm
+      m2 = Get<1>::of<stats_t, T>(result);
+    }
+
+    warp_chan_upd_dynamic<isRMSNorm>(m, m2, n, WARPS_N);
+
+    return {m, m2};
+  }
+
+  WarpStats warp_stats_;
+  stats_t* smem0_;
+  stats_t* smem1_;
+  bool use0_;
+};
+
+template <typename T, uint32_t WARPS_M, bool USE_CLUSTER, bool WHOLE_CTA>
+struct Stats<T, 1, WARPS_M, 1, USE_CLUSTER, WHOLE_CTA> {
+  using stats_t = typename TypeToVec2<T>::Type;
+  // The simple Warp reducer.
+  using Reducer = Reducer<T, 1, WARPS_M, 1, USE_CLUSTER, WHOLE_CTA>;
+
+  enum { SMEM_BYTES = 0 };
+
+  template <typename Params>
+  inline __device__ Stats(Params& params, uint32_t bidm, uint32_t bidn, uint32_t warp_m,
+                          uint32_t warp_n, uint32_t tidx, uint32_t lane, void* smem,
+                          uint64_t* smem_bar)
+      : reducer_(params, bidm, bidn, warp_m, warp_n, tidx, lane, smem, smem_bar) {}
+
+  template <bool isRMSNorm, uint32_t LDGS, uint32_t NUM_ELTS>
+  inline __device__ stats_t compute(const T (&elts)[LDGS * NUM_ELTS], const T rn, int32_t warps_m) {
+    static constexpr uint32_t N = LDGS * NUM_ELTS;
+    auto sum = Sum<T>();
+
+    T m = Zeros<T>::get();
+    if (!isRMSNorm) {
+// CL-14115: The unroll factor 128 for LDGS was chosen based on the compilation/perf results for
+// APEX LN_fwd engines
+#pragma unroll(128 * NUM_ELTS)
+      for (int it = 0; it < N; it++) {
+        m += elts[it];
+      }
+      m = reducer_.allreduce(m, sum, warps_m) * rn;
+    }
+
+    T m2 = Zeros<T>::get();
+#pragma unroll(128 * NUM_ELTS)
+    for (int it = 0; it < N; it++) {
+      T diff = (elts[it] - m);
+      m2 = __fmaf_ieee_rn(diff, diff, m2);
+    }
+    m2 = reducer_.allreduce(m2, sum, warps_m);
+
+    return {m, m2};
+  }
+
+  Reducer reducer_;
+};
