+template <typename weight_t_, typename input_t_, typename output_t_, typename compute_t_,
+          typename norm_output_t_, typename index_t_, uint32_t HIDDEN_SIZE_, uint32_t BATCH_SIZE_,
+          uint32_t CTAS_PER_ROW_, uint32_t WARPS_M_, uint32_t WARPS_N_,
+          uint32_t BYTES_PER_LDG_ = 16, bool isRMSNorm_ = false, bool isAdaLN_ = false,
+          bool isBatchFirst_ = true, bool hasGamma_ = true, bool hasBeta_ = true,
+          bool useGammaSmem_ =
+              true,  // for FWD kernels it denotes the use of shmem for both gamma and beta
+          bool useCluster_ = false, bool wholeCTA_ = false, uint32_t ROWS_PER_WARP_ = 1,
+          typename Base =
+              Kernel_traits_base<HIDDEN_SIZE_, weight_t_, input_t_, output_t_, compute_t_, index_t_,
+                                 WARPS_M_ * WARPS_N_ * THREADS_PER_WARP> >
+struct Kernel_traits : public Base {
+  using input_t = typename Base::input_t;
+  using weight_t = typename Base::weight_t;
+  using compute_t = typename Base::compute_t;
+  using output_t = typename Base::output_t;
+  using index_t = typename Base::index_t;
+  using norm_output_t = norm_output_t_;
+  enum { isRMSNorm = isRMSNorm_ };
+  enum { isAdaLN = isAdaLN_ };
+  enum { isBatchFirst = isBatchFirst_ };
+  enum { hasGamma = hasGamma_ };
+  enum { hasBeta = hasBeta_ };
+  enum { CTAS_PER_ROW = CTAS_PER_ROW_ };
+  enum { WARPS_M = WARPS_M_ };
+  enum { WARPS_N = WARPS_N_ };
+  enum { COLS = HIDDEN_SIZE_ };
+  enum { HIDDEN_SIZE = HIDDEN_SIZE_ };
+  enum { BATCH_SIZE = BATCH_SIZE_ };
+  enum { BYTES_PER_LDG = BYTES_PER_LDG_ };
+  enum { NUM_ELTS = BYTES_PER_LDG / sizeof(input_t) };
+  enum { USE_GAMMA_SMEM = useGammaSmem_ };
+  enum { USE_CLUSTER = useCluster_ };
+  enum { WHOLE_CTA = wholeCTA_ };
+  enum { THREADS_PER_ROW = WARPS_N * THREADS_PER_WARP };
+  enum { THREADS_PER_CTA = WARPS_M * THREADS_PER_ROW };
+  enum { ROWS_PER_WARP = ROWS_PER_WARP_ };
+  enum { ROWS_PER_CTA = WARPS_M * ROWS_PER_WARP };
+
+  enum { BYTES_PER_ROW = COLS * sizeof(input_t) };
+  enum { BYTES_PER_ROW_PER_CTA = THREADS_PER_ROW * BYTES_PER_LDG };
+  // Multi-row per CTA not supported for multi-CTA => no smem for WGRAD needed
+  enum {
+    SMEM_BYTES_WGRAD = ROWS_PER_CTA == 1 ? 0 : BATCH_SIZE * ROWS_PER_CTA * COLS * sizeof(compute_t)
+  };
+
+  using reduce_t = typename TypeToVec2<compute_t>::Type;
+  using RMSReducer = Reducer<compute_t, CTAS_PER_ROW, WARPS_M, WARPS_N, USE_CLUSTER, WHOLE_CTA>;
+  using Reducer = Reducer<reduce_t, CTAS_PER_ROW, WARPS_M, WARPS_N, USE_CLUSTER, WHOLE_CTA>;
+
+  enum { SMEM_BYTES_DGRAD = Reducer::SMEM_BYTES };
+  enum { SMEM_BYTES = SMEM_BYTES_DGRAD + SMEM_BYTES_WGRAD };
+
+  using Ivec = Vec<input_t, NUM_ELTS>;
+  using Ovec = Vec<output_t, NUM_ELTS>;
+  using Wvec = Vec<weight_t, NUM_ELTS>;
+  using Cvec = Vec<compute_t, NUM_ELTS>;
+  using NormOvec = Vec<norm_output_t, NUM_ELTS>;
+  enum { ELTS_PER_LDG = BYTES_PER_LDG / sizeof(input_t) };
+
+  // Assume that each thread can handle the same number of elements in the output and weights as in
+  // the input. The number of columns fetched per load from input: one per thread.
+  enum { VEC_COLS_PER_LDG = CTAS_PER_ROW * THREADS_PER_ROW };
+  // The total number of vectorized loads/stores per hidden vector.
+  enum { VEC_COLS = COLS / ELTS_PER_LDG };
+  // The number of loads per thread for the input.
+  enum { LDGS = VEC_COLS / VEC_COLS_PER_LDG };
+
+  using Stats = Stats<compute_t, CTAS_PER_ROW, WARPS_M, WARPS_N, USE_CLUSTER, WHOLE_CTA>;
+  enum { SMEM_BYTES_FWD = Stats::SMEM_BYTES };
+};
