+
+constexpr float LN_FLT_MIN =
+    1.17549435082228750796873653722224568e-38F;  // Minimum positive normalized float value
+/**
+ * Base class to provide common block scaling utilities, private to `BlockScaleHelper`
+ */
+template <typename Cvec, typename Ovec, int32_t BlockSize>
+class BlockScaleHelperBase;
+
+/**
+ * Base class to provide common block scaling utilities, for nvfp4
+ */
+template <typename Cvec, typename Ovec>
+class BlockScaleHelperBase<Cvec, Ovec, 16> {
+ public:
+  using scale_t = nv_fp8_e4m3;
+
+ protected:
+  using compute_t = typename Cvec::Elt_type;
+  using output_t = typename Ovec::Elt_type;
+
+  using index_t = uint32_t;
+
+  static constexpr int32_t THREADS_PER_WARP = 32;
+  static constexpr int32_t BLOCK_SIZE = 16;
+  static constexpr int32_t NUM_ELTS = sizeof(Cvec) / sizeof(compute_t);
+  static constexpr int32_t GROUP_SIZE = BLOCK_SIZE / NUM_ELTS;
+  static constexpr int32_t SF_COUNT = THREADS_PER_WARP / GROUP_SIZE;
+
+  static __device__ compute_t scale(const compute_t value) {
+    constexpr compute_t nvfp4_max = 6.0f;
+    compute_t result = value / nvfp4_max;
+    // Clamp to LN_FLT_MIN to match reference implementation and avoid 0 scaling factors
+    return fmaxf(result, LN_FLT_MIN);
+  }
+
+  static __device__ scale_t fp32ToE4M3(float value) { return scale_t(value); }
+
+  static __device__ Vec<uint8_t, NUM_ELTS> vecDivideAndCast(const Cvec& input, compute_t scale) {
+    // Construct the nv_fp4x2_e2m1 outputs.
+    // If NUM_ELTS == 1, nv_fp4(ele1,0)
+    // If NUM_ELTS % 2 == 0; f2_i=nv_fp4(ele_i, ele_i+1) --> out[i/2]
+    // Per cuda_fp4.h and cuda_fp8.h
+    // The data type of  __nv_fp4x2_storage_t is __nv_fp8_storage_t
+    // The data type of __nv_fp8_storage_t is unsigned char:
+    // typedef unsigned char __nv_fp8_storage_t;
+    // The reason why we use  unsigned char is that the __shfl_xor_sync don't support nv_fp4 data
+    // type
+    Vec<uint8_t, NUM_ELTS> output;
+#pragma unroll
+    for (int i = 0; i < NUM_ELTS; i += 2) {
+      float2 f2 = make_float2((input.data.elt[i] / scale),
+                              (i + 1 < NUM_ELTS ? (input.data.elt[i + 1] / scale) : 0));
+      output.data.elt[i / 2] = static_cast<uint8_t>(nv_fp4x2_e2m1(f2).__x);
+    }
+    return output;
+  }
+};
+
+/**
+ * Base class to provide common block scaling utilities, for mxfp8
+ */
+template <typename Cvec, typename Ovec>
+class BlockScaleHelperBase<Cvec, Ovec, 32> {
+ public:
+  using lne8m0_t = uint8_t;
+  using scale_t = lne8m0_t;
+
+ protected:
+  using compute_t = typename Cvec::Elt_type;
+  using output_t = typename Ovec::Elt_type;
+  using index_t = uint32_t;
+
+  static constexpr int32_t THREADS_PER_WARP = 32;
+  static constexpr int32_t BLOCK_SIZE = 32;
+  static constexpr int32_t NUM_ELTS = sizeof(Cvec) / sizeof(compute_t);
+  static constexpr int32_t GROUP_SIZE = BLOCK_SIZE / NUM_ELTS;
+
+  static __device__ compute_t scale(const compute_t value) {
+    static constexpr float FP8_MAX = std::is_same<output_t, nv_fp8_e5m2>::value ? 57344.f : 448.f;
+    compute_t result = value / FP8_MAX;
+    // Clamp to LN_FLT_MIN to match reference implementation and avoid 0 scaling factors
+    return fmaxf(result, LN_FLT_MIN);
+  }
+
+  template <typename IOvec>
+  static __device__ Ovec vecDivideAndCast(const IOvec& input, compute_t scale) {
+    Ovec output;
+#pragma unroll
+    for (int32_t i = 0; i < NUM_ELTS; ++i) {
+      output.data.elt[i] = output_t((compute_t(input.data.elt[i]) / scale));
+    }
+    return output;
+  };
+};
+
+/**
+ * Helper class to define the block scale operations
+ */
+template <typename Cvec, typename Ovec, int32_t BlockSize>
+class BlockScaleRowHelper;
+
+template <typename Cvec, typename Ovec, int32_t BlockSize>
+class BlockScaleColHelper;
+
+/**
+ * Specialization for MXFP8 rowwise scaling
+ */
+template <typename Cvec, typename Ovec>
+class BlockScaleRowHelper<Cvec, Ovec, 32> : private BlockScaleHelperBase<Cvec, Ovec, 32> {
+ private:
+  using Base = BlockScaleHelperBase<Cvec, Ovec, 32>;
+  using Base::BLOCK_SIZE;
+  using Base::GROUP_SIZE;
+  using Base::NUM_ELTS;
+  using Base::THREADS_PER_WARP;
+  using typename Base::compute_t;
+  using typename Base::index_t;
+  using typename Base::scale_t;
+
+ public:
+  __device__ BlockScaleRowHelper() = default;
+
+  template <typename IOvec>
+  __device__ void blockQuantizeStore(const IOvec& z_math, void* sf_ptr, index_t sf_idx, void* z_ptr,
+                                     index_t z_idx) {
+    const index_t group_id = lane / GROUP_SIZE;
+
+    // 1. compute scaling factor
+    compute_t sf = 0;
+#pragma unroll
+    // compute the amax across NUM_ELTS elements
+    for (int jt = 0; jt < NUM_ELTS; jt++) {
+      sf = fmaxf(sf, fabsf(compute_t(z_math.data.elt[jt])));
+    }
+
+// Currently disabled for rowwise block scaling as perf regression observed
+#if 0 && (defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 1000) && defined(__CUDA_ARCH_FEAT_SM100_ALL)
+#pragma unroll
+        for (int jt = 0; jt < NUM_ELTS; jt++) {
+            if (group_id == jt) {
+                asm volatile("redux.sync.max.f32 %0, %1, %2;" : "=f"(sf) : "f"(sf), "r"(__activemask()));
+            }
+        }
+#else
+    // warp reduce (binary reduction) starting from GROUP_SIZE / 2 to aggregate
+    // a total of NUM_ELTS * GROUP_SIZE = BLOCK_SIZE number of z values in sf
+#pragma unroll
+    for (int offset = GROUP_SIZE / 2; offset > 0; offset /= 2) {
+      sf = fmaxf(sf, __shfl_down_sync(0xffffffff, sf, offset));
+    }
+
+    // broadcast from the lane with the valid values to the other threads in the group
+    sf = __shfl_sync(0xffffffff, sf, group_id * GROUP_SIZE);
+#endif
+    // scale the row amax to get the scaling factor
+    sf = Base::scale(sf);
+
+    // 2. store scaling factor
+    // Warp orchestration to compute scale_row:
+    // e.g. for NUM_ELTS == 2:
+    //   |  W0SF0 W0SF1  |  W0SF0 W0SF1  | ... |        W0SF0 W0SF1       |  W0SF0 W0SF1  |...
+    //   |  W1SF0 W1SF1  |  W1SF0 W1SF1  | ... |        W1SF0 W1SF1       |  W1SF0 W1SF1  |...
+    //   |      ...      |      ...      | ... |            ...           |      ...      |...
+    //   | W31SF0 W31SF1 | W31SF0 W31SF1 | ... |        W31SF0 W31SF1     | W31SF0 W31SF1 |...
+    //   |---------------|---------------|-----|--------------------------|---------------|...
+    //   |----- CTA0 ----|----- CTA1 ----| ... |--- CTA<ctas_per_row-1> --|----- CTA0 ----|...
+    //   |                                                                |
+    //   |-------------------------------LDG0-----------------------------|-------LDG1-----...
+    Vec<scale_t, NUM_ELTS> sf_out;
+    // only correct for group_id == 0, but it's ok because only lane == 0 is storing sf_out
+    sf_out.data.elt[0] = float_to_e8m0(sf);
+#pragma unroll
+    for (int jt = 1; jt < NUM_ELTS; jt++) {
+      sf_out.data.elt[jt] = float_to_e8m0(__shfl_sync(0xffffffff, sf, jt * GROUP_SIZE));
+    }
+    if (lane == 0) {
+      sf_out.store_to(sf_ptr, sf_idx);
+    }
+    // No need to check for 0x00 - scale() now clamps to FLT_MIN which converts to 0x01
+    float scale = e8m0_to_float(sf_out.data.elt[0]);
+    Ovec z_row_scaled = Base::vecDivideAndCast(z_math, scale);
+    z_row_scaled.store_to(z_ptr, z_idx);
+  }
+
+ private:
+  const index_t lane = threadIdx.x % THREADS_PER_WARP;
+};
+
+/**
+ * Specialization for MXFP8 colwise scaling in 1D2X2X
+ */
+template <typename Cvec, typename Ovec>
+class BlockScaleColHelper<Cvec, Ovec, 32> : private BlockScaleHelperBase<Cvec, Ovec, 32> {
+ private:
+  using Base = BlockScaleHelperBase<Cvec, Ovec, 32>;
+  using Base::BLOCK_SIZE;
+  using Base::GROUP_SIZE;
+  using Base::NUM_ELTS;
+  using Base::THREADS_PER_WARP;
+  using typename Base::compute_t;
+  using typename Base::index_t;
+  using typename Base::output_t;
+  using typename Base::scale_t;
+
+ public:
+  __device__ BlockScaleColHelper(float* mxfp8_tile) : mxfp8_tile_(mxfp8_tile) {}
+
+  template <typename IOvec>
+  __device__ void initTile(const IOvec& z_math, int num_threads) {
+    return initTile(z_math, warp, num_threads);
+  }
+
+  template <typename IOvec>
+  __device__ void initTile(const IOvec& z_math, index_t row_in_tile, int num_threads) {
+    constexpr int entry_barrier_arbitrary = 5;
+    utils::namedBarrierSync(entry_barrier_arbitrary, num_threads);
+#pragma unroll
+    for (index_t jt = 0; jt < NUM_ELTS; jt++) {
+      index_t idx_in_mxfp8_smem =
+          (jt * (BLOCK_SIZE + /*padding row*/ 1) + row_in_tile) * MXFP8_1D2X2X_SMEM_COLS + lane;
+      mxfp8_tile_[idx_in_mxfp8_smem] = float(z_math.data.elt[jt]);
+    }
+  }
+
+  template <bool Transpose>
+  __device__ void blockQuantizeStore(void* sf_ptr, index_t sf_row_idx, index_t sf_col_idx,
+                                     index_t sf_row_width, void* z_ptr, index_t z_idx,
+                                     int num_threads) {
+    return blockQuantizeStore<Transpose>(sf_ptr, sf_row_idx, sf_col_idx, sf_row_width, z_ptr, z_idx,
+                                         num_threads, warp);
+  }
+
+  template <bool Transpose>
+  __device__ void blockQuantizeStore(void* sf_ptr, index_t sf_row_idx, index_t sf_col_idx,
+                                     index_t sf_row_width, void* z_ptr, index_t z_idx,
+                                     int num_threads, index_t row_in_tile) {
+    // Ensure all temp outputs have been written to mxfp8 smem for the current ldg
+    constexpr int entry_barrier_arbitrary = 4;
+    utils::namedBarrierSync(entry_barrier_arbitrary, num_threads);
+    const index_t group_id = lane / GROUP_SIZE;
+
+#if (defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 1000) && defined(__CUDA_ARCH_FEAT_SM100_ALL)
+    // For sm_100a arch, we can use redux.sync.op{.abs.}{.NaN}.f32 instruction to reduce the min/max
+    // value
+    // https://docs.nvidia.com/cuda/parallel-thread-execution/#parallel-synchronization-and-communication-instructions-redux-sync
+    compute_t amax_vals[NUM_ELTS];
+#pragma unroll
+    for (int jt = 0; jt < NUM_ELTS; jt++) {
+      const index_t idx_in_mxfp8_smem =
+          jt * NEXT_COL_SMEM_OFFSET + lane * MXFP8_1D2X2X_SMEM_COLS + row_in_tile;
+      asm volatile("redux.sync.max.abs.f32 %0, %1, 0xffffffff;"
+                   : "=f"(amax_vals[jt])
+                   : "f"(mxfp8_tile_[idx_in_mxfp8_smem]));
+    }
+    compute_t sf = amax_vals[group_id];
+#else
+    // 1. compute scaling factor
+    compute_t sf = 0;
+#pragma unroll
+    // compute the amax across NUM_ELTS elements in the same col (in shared memory, adjacent rows)
+    for (int jt = 0; jt < NUM_ELTS * MXFP8_1D2X2X_SMEM_COLS; jt += MXFP8_1D2X2X_SMEM_COLS) {
+      const index_t idx_in_mxfp8_smem = ROW_SMEM_OFFSET + jt + row_in_tile;
+      sf = fmaxf(sf, fabsf(mxfp8_tile_[idx_in_mxfp8_smem]));
+    }
+
+    // warp reduce (binary reduction) starting from GROUP_SIZE / 2 to aggregate
+    // a total of NUM_ELTS * GROUP_SIZE = BLOCK_SIZE number of z values in sf
+#pragma unroll
+    for (int offset = GROUP_SIZE / 2; offset > 0; offset /= 2) {
+      sf = fmaxf(sf, __shfl_down_sync(0xffffffff, sf, offset));
+    }
+
+    // broadcast from the lane with the valid values to the other threads in the group
+    sf = __shfl_sync(0xffffffff, sf, group_id * GROUP_SIZE);
+#endif
+
+    // scale the col amax to get the scaling factor
+    sf = Base::scale(sf);
+
+    // Warp orchestration to compute scale_col:
+    // e.g. for NUM_ELTS == 2:
+    //   | W0SF0 W0SF1 W1SF0 W1SF1 ... W31SF0 W31SF1 | W0SF0 W0SF1 ... W31SF0 W31SF1 |...
+    //   |----warp0---|---warp1--| ... |----warp31---|----warp0---|... |----warp31---|...
+    //   |--------------------CTA0-------------------|---------------CTA1------------|...
+    //   |------------------------------------------LDG0------------------------------...
+    Ovec z_col_scaled;
+    if constexpr (!Transpose) {
+      // 2. store scaling factor
+      // different columns require different sf, so all threads must exchange sf
+      Vec<scale_t, NUM_ELTS> sf_out;
+#pragma unroll
+      for (int jt = 0; jt < NUM_ELTS; jt++) {
+        sf_out.data.elt[jt] = float_to_e8m0(__shfl_sync(0xffffffff, sf, jt * GROUP_SIZE));
+      }
+      if (lane == 0) {
+        sf_out.store_to(sf_ptr, sf_row_idx * sf_row_width + sf_col_idx);
+      }
+
+      // 3. scale and store output
+#pragma unroll
+      for (int jt = 0; jt < NUM_ELTS; jt++) {
+        // iterate over NUM_ELTS elements in a row (in shared memory, every other NUM_ELTS in a
+        // column)
+        index_t z_idx_in_mxfp8_smem =
+            jt * NEXT_COL_SMEM_OFFSET + lane * MXFP8_1D2X2X_SMEM_COLS + row_in_tile;
+        // No need to check for 0x00 - scale() now clamps to FLT_MIN which converts to 0x01
+        float scale = e8m0_to_float(sf_out.data.elt[jt]);
+        z_col_scaled.data.elt[jt] = output_t(mxfp8_tile_[z_idx_in_mxfp8_smem] / scale);
+      }
+    } else {
+      // 2. store scaling factor
+      uint8_t sf_e8m0 = float_to_e8m0(sf);
+      // No need to check for 0x00 - scale() now clamps to FLT_MIN which converts to 0x01
+      if (lane % GROUP_SIZE == 0) {
+        static_cast<scale_t*>(sf_ptr)[(sf_row_idx + group_id) * sf_row_width + sf_col_idx] =
+            sf_e8m0;
+      }
+
+      // 3. scale and store output
+      float scale = e8m0_to_float(sf_e8m0);
+      // No need to check for 0.0f - scale() now clamps to FLT_MIN
+#pragma unroll
+      for (int jt = 0; jt < NUM_ELTS; jt++) {
+        // iterate over NUM_ELTS elements in a column (in shared memory, adjacent NUM_ELTS rows)
+        index_t z_idx_in_mxfp8_smem = ROW_SMEM_OFFSET + jt * MXFP8_1D2X2X_SMEM_COLS + row_in_tile;
+        z_col_scaled.data.elt[jt] = output_t(mxfp8_tile_[z_idx_in_mxfp8_smem] / scale);
+      }
+    }
+    z_col_scaled.store_to(z_ptr, z_idx);
+  }
+
+ private:
+  static constexpr index_t MXFP8_1D2X2X_SMEM_ROWS =
+      BLOCK_SIZE * NUM_ELTS + /*padding rows between*/ (NUM_ELTS - 1);
+  static constexpr index_t MXFP8_1D2X2X_SMEM_COLS = BLOCK_SIZE + /*padding col*/ 1;
+  static constexpr index_t NEXT_COL_SMEM_OFFSET =
+      (BLOCK_SIZE + /*padding row*/ 1) * MXFP8_1D2X2X_SMEM_COLS;
+  // For MXFP8 1d2x2x, we store the 32x32xNUM_ELTS tile in shared memory to compute the col amax for
+  // scaling within the current CTA e.g. for NUM_ELTS == 2, the shared memory layout for 1d2x2x is
+  // as follows:
+  //
+  //     col0   col2   col4   col6  ...  col62
+  //      ↓      ↓      ↓      ↓           ↓
+  //   |-------------------------------------------|
+  //   | T0V0 | T1V0 | T2V0 | T3V0 |...| T31V0 | 0 |  <-- warp0  to store at jt=0
+  //   | T0V0 | T1V0 | T2V0 | T3V0 |...| T31V0 | 0 |  <-- warp1  to store at jt=0
+  //   |  ..  |  ..  |  ..  |  ..  |...|  ...  | 0 |  <-- ...
+  //   | T0V0 | T1V0 | T2V0 | T3V0 |...| T31V0 | 0 |  <-- warp31 to store at jt=0
+  //   |--------------------|------|---|-------|---|
+  //   |  0   |  0   |  0   |  0   |...|   0   | 0 |  <-- padding row between to avoid bank
+  //   conflicts when col-scaling
+  //   |--------------------|------|---|-------|---|
+  //   | T0V1 | T1V1 | T2V1 | T3V1 |...| T31V1 | 0 |  <-- warp0  to store at jt=1
+  //   | T0V1 | T1V1 | T2V1 | T3V1 |...| T31V1 | 0 |  <-- warp1  to store at jt=1
+  //   |  ..  |  ..  |  ..  |  ..  |...|  ...  | 0 |  <-- ...
+  //   | T0V1 | T1V1 | T2V1 | T3V1 |...| T31V1 | 0 |  <-- warp31 to store at jt=1
+  //   |-------------------------------------------|
+  //      ↑      ↑      ↑      ↑           ↑     ↑
+  //     col1   col3   col5   col7  ...  col63   padding col to avoid bank conflicts when computing
+  //     col-scale factors
+  //
+  //      ↑      ↑      ↑      ↑           ↑
+  //    warp0  warp1  warp2  warp3  ...  warp31
+  //  to compute and apply the col-scale factors
+  float* mxfp8_tile_ = nullptr;
+
+  const index_t lane = threadIdx.x % THREADS_PER_WARP;
+  const index_t warp = threadIdx.x / THREADS_PER_WARP;
+
+  const index_t ROW_SMEM_OFFSET =
+      ((lane * NUM_ELTS) + /*padding rows*/ (lane / GROUP_SIZE)) * MXFP8_1D2X2X_SMEM_COLS;
+};
+
+/**
+ * Specialization for NVFP4 rowwise scaling
+ */
+template <typename Cvec, typename Ovec>
+class BlockScaleRowHelper<Cvec, Ovec, 16> : private BlockScaleHelperBase<Cvec, Ovec, 16> {
+  using Base = BlockScaleHelperBase<Cvec, Ovec, 16>;
+  using Base::BLOCK_SIZE;
+  using Base::GROUP_SIZE;
+  using Base::NUM_ELTS;
+  using Base::SF_COUNT;
+  using Base::THREADS_PER_WARP;
+  using typename Base::compute_t;
+  using typename Base::index_t;
+  using typename Base::output_t;
+  using typename Base::scale_t;
+
+ public:
+  __device__ BlockScaleRowHelper() = default;
+
+  __device__ void blockQuantizeStore(const Cvec& z_math, void* sf_ptr, index_t sf_idx, void* z_ptr,
+                                     index_t z_idx) {
+    // 1. compute scaling factor
+    compute_t sf = 0;
+#pragma unroll
+    // compute the amax across NUM_ELTS elements
+    for (int jt = 0; jt < NUM_ELTS; jt++) {
+      sf = fmaxf(sf, fabsf(z_math.data.elt[jt]));
+    }
+
+    // warp reduce (binary reduction) starting from GROUP_SIZE / 2 to aggregate
+    // a total of NUM_ELTS * GROUP_SIZE = BLOCK_SIZE number of z values in sf
+#pragma unroll
+    for (int offset = GROUP_SIZE / 2; offset > 0; offset /= 2) {
+      sf = fmaxf(sf, __shfl_down_sync(0xffffffff, sf, offset));
+    }
+
+    // broadcast from the lane with the valid values to the other threads in the group
+    const index_t group_id = lane / GROUP_SIZE;
+    sf = __shfl_sync(0xffffffff, sf, group_id * GROUP_SIZE);
+
+    // scale the row amax to get the scaling factor
+    sf = Base::scale(sf);
+
+    // 2. store scaling factor
+    Vec<scale_t, SF_COUNT> sf_out;
+    // only correct for group_id == 0, but it's ok because only lane == 0 is storing sf_out
+    sf_out.data.elt[0] = Base::fp32ToE4M3(sf);
+#pragma unroll
+    for (int jt = 1; jt < SF_COUNT; jt++) {
+      sf_out.data.elt[jt] = Base::fp32ToE4M3(__shfl_sync(0xffffffff, sf, jt * GROUP_SIZE));
+    }
+    if (lane == 0) {
+      sf_out.store_to(sf_ptr, sf_idx);
+    }
+
+    // TODO: can consider doing something like the following to remove the need for a shuffle loop
+    // template <int32_t N>
+    // struct UintContainer {
+    //     using type = std::conditional_t<N == 1, uint8_t,
+    //                  std::conditional_t<N == 2, uint16_t,
+    //                  std::conditional_t<N == 4, uint32_t,
+    //                  std::conditional_t<N == 8, uint64_t,
+    //                  void>>>>;  // void for unsupported sizes
+    // };
+    // Base::vecDivideAndCast returns Vec<UintContainer<NUM_ELTS / 2>, 2>
+    // 3. scale and store output
+    auto z_row_scaled = Base::vecDivideAndCast(z_math, sf);
+#pragma unroll
+    // Consturct z_row_scaled by combining the adjacent thread's z_row_scaled
+    // Vec<uint8_t, NUM_ELTS> z_row_scaled
+    for (int i = 0; i < NUM_ELTS / 2; i++) {
+      uint8_t adjacent_val = __shfl_xor_sync(0xffffffff, z_row_scaled.data.elt[i], 1);
+      z_row_scaled.data.elt[i + NUM_ELTS / 2] = adjacent_val;
+    }
+    if (NUM_ELTS == 1) {
+      uint8_t adjacent_val = __shfl_xor_sync(0xffffffff, z_row_scaled.data.elt[0], 1);
+      z_row_scaled.data.elt[0] |= adjacent_val << 4U;
+    }
+    if (lane % 2 == 0) {
+      z_row_scaled.store_to(z_ptr, z_idx / 2);
+    }
+  }
+
+ private:
+  const index_t lane = threadIdx.x % THREADS_PER_WARP;
+};
